import EVENTS from '/../backend/events.json';
import { Link } from 'react-router-dom';

function EventsPage() {
    return <>
        <h1>Events Page</h1>

        <ul>
            {EVENTS.map((eventy) => (
                <li key={eventy.id}>
                    <Link to={`/events/${eventy.id}`}>{eventy.title}</Link>
                </li>
            ))}
        </ul>
    </>
}

export default EventsPage;
